// Cloudflare Worker for Edge Authentication System
// KV Namespaces needed:
// - USERS_DB: stores user records (key: "user:{username}", value: JSON with password_hash, email, etc.)
// - SESSIONS: stores session tokens (key: "session:{token}", value: JSON with username, created_at, expires_at)
// - CONFIG: stores configuration like API keys, connection strings (key: "db_connection_string", "api_key", etc.)

export default {
  async fetch(request, env, ctx) {
    const url = new URL(request.url);
    const corsHeaders = {
      "Access-Control-Allow-Origin": "*",
      "Access-Control-Allow-Methods": "POST, GET, DELETE, OPTIONS",
      "Access-Control-Allow-Headers": "Content-Type, Authorization",
    };

    if (request.method === "OPTIONS") {
      return new Response(null, { status: 204, headers: corsHeaders });
    }

    try {
      if (url.pathname === "/auth/register" && request.method === "POST") {
        return await handleRegister(request, env, corsHeaders);
      }

      if (url.pathname === "/auth/login" && request.method === "POST") {
        return await handleLogin(request, env, corsHeaders);
      }

      if (url.pathname === "/auth/logout" && request.method === "POST") {
        return await handleLogout(request, env, corsHeaders);
      }

      if (url.pathname === "/auth/validate" && request.method === "GET") {
        return await handleValidate(request, env, corsHeaders);
      }

      if (url.pathname === "/auth/refresh" && request.method === "POST") {
        return await handleRefresh(request, env, corsHeaders);
      }

      return jsonResponse({ error: "Not Found" }, 404, corsHeaders);
    } catch (err) {
      return jsonResponse({ error: "Internal Server Error", message: err.message }, 500, corsHeaders);
    }
  },
};

async function handleRegister(request, env, corsHeaders) {
  const body = await request.json();
  const { username, password, email } = body;

  if (!username || !password) {
    return jsonResponse({ error: "Username and password are required" }, 400, corsHeaders);
  }

  if (username.length < 3 || username.length > 50) {
    return jsonResponse({ error: "Username must be between 3 and 50 characters" }, 400, corsHeaders);
  }

  if (password.length < 8) {
    return jsonResponse({ error: "Password must be at least 8 characters" }, 400, corsHeaders);
  }

  const existingUser = await env.USERS_DB.get(`user:${username.toLowerCase()}`);
  if (existingUser) {
    return jsonResponse({ error: "Username already exists" }, 409, corsHeaders);
  }

  const salt = generateSalt();
  const passwordHash = await hashPassword(password, salt);

  const userRecord = {
    username: username.toLowerCase(),
    password_hash: passwordHash,
    salt: salt,
    email: email || null,
    created_at: new Date().toISOString(),
    updated_at: new Date().toISOString(),
    active: true,
  };

  await env.USERS_DB.put(`user:${username.toLowerCase()}`, JSON.stringify(userRecord));

  const sessionToken = await generateSessionToken();
  const sessionData = {
    username: username.toLowerCase(),
    created_at: new Date().toISOString(),
    expires_at: new Date(Date.now() + 24 * 60 * 60 * 1000).toISOString(),
    user_agent: request.headers.get("User-Agent") || "unknown",
    ip: request.headers.get("CF-Connecting-IP") || "unknown",
  };

  const sessionTTL = 24 * 60 * 60; // 24 hours in seconds
  await env.SESSIONS.put(`session:${sessionToken}`, JSON.stringify(sessionData), {
    expirationTtl: sessionTTL,
  });

  return jsonResponse(
    {
      message: "User registered successfully",
      session_token: sessionToken,
      expires_at: sessionData.expires_at,
      username: username.toLowerCase(),
    },
    201,
    corsHeaders
  );
}

async function handleLogin(request, env, corsHeaders) {
  const body = await request.json();
  const { username, password } = body;

  if (!username || !password) {
    return jsonResponse({ error: "Username and password are required" }, 400, corsHeaders);
  }

  const rateLimitKey = `ratelimit:login:${username.toLowerCase()}`;
  const rateLimitData = await env.SESSIONS.get(rateLimitKey);
  if (rateLimitData) {
    const rateLimit = JSON.parse(rateLimitData);
    if (rateLimit.attempts >= 5) {
      const lockoutEnd = new Date(rateLimit.locked_until);
      if (new Date() < lockoutEnd) {
        return jsonResponse(
          {
            error: "Too many failed attempts. Account temporarily locked.",
            locked_until: rateLimit.locked_until,
          },
          429,
          corsHeaders
        );
      }
    }
  }

  const userDataRaw = await env.USERS_DB.get(`user:${username.toLowerCase()}`);
  if (!userDataRaw) {
    await incrementLoginAttempts(env, rateLimitKey, rateLimitData);
    return jsonResponse({ error: "Invalid username or password" }, 401, corsHeaders);
  }

  const userData = JSON.parse(userDataRaw);

  if (!userData.active) {
    return jsonResponse({ error: "Account is deactivated" }, 403, corsHeaders);
  }

  const passwordHash = await hashPassword(password, userData.salt);
  const isValid = timingSafeEqual(passwordHash, userData.password_hash);

  if (!isValid) {
    await incrementLoginAttempts(env, rateLimitKey, rateLimitData);
    return jsonResponse({ error: "Invalid username or password" }, 401, corsHeaders);
  }

  // Clear rate limit on successful login
  await env.SESSIONS.delete(rateLimitKey);

  const sessionToken = await generateSessionToken();
  const sessionTTL = 24 * 60 * 60; // 24 hours
  const sessionData = {
    username: username.toLowerCase(),
    created_at: new Date().toISOString(),
    expires_at: new Date(Date.now() + sessionTTL * 1000).toISOString(),
    user_agent: request.headers.get("User-Agent") || "unknown",
    ip: request.headers.get("CF-Connecting-IP") || "unknown",
  };

  await env.SESSIONS.put(`session:${sessionToken}`, JSON.stringify(sessionData), {
    expirationTtl: sessionTTL,
  });

  // Update last login
  userData.last_login = new Date().toISOString();
  userData.updated_at = new Date().toISOString();
  await env.USERS_DB.put(`user:${username.toLowerCase()}`, JSON.stringify(userData));

  // Log the authentication event if API key is configured
  const apiKey = await env.CONFIG.get("api_key");
  if (apiKey) {
    // Could send audit log to external service here
    // ctx.waitUntil(logAuthEvent(env, apiKey, username, "login"));
  }

  return jsonResponse(
    {
      message: "Login successful",
      session_token: sessionToken,
      expires_at: sessionData.expires_at,
      username: username.toLowerCase(),
    },
    200,
    corsHeaders
  );
}

async function handleLogout(request, env, corsHeaders) {
  const authHeader = request.headers.get("Authorization");
  if (!authHeader || !authHeader.startsWith("Bearer ")) {
    return jsonResponse({ error: "Authorization header required" }, 401, corsHeaders);
  }

  const token = authHeader.substring(7);
  const sessionKey = `session:${token}`;
  const sessionData = await env.SESSIONS.get(sessionKey);

  if (!sessionData) {
    return jsonResponse({ error: "Invalid or expired session" }, 401, corsHeaders);
  }

  await env.SESSIONS.delete(sessionKey);

  return jsonResponse({ message: "Logged out successfully" }, 200, corsHeaders);
}

async function handleValidate(request, env, corsHeaders) {
  const authHeader = request.headers.get("Authorization");
  if (!authHeader || !authHeader.startsWith("Bearer ")) {
    return jsonResponse({ error: "Authorization header required", valid: false }, 401, corsHeaders);
  }

  const token = authHeader.substring(7);
  const sessionKey = `session:${token}`;
  const sessionDataRaw = await env.SESSIONS.get(sessionKey);

  if (!sessionDataRaw) {
    return jsonResponse({ error: "Invalid or expired session", valid: false }, 401, corsHeaders);
  }

  const sessionData = JSON.parse(sessionDataRaw);
  const expiresAt = new Date(sessionData.expires_at);

  if (new Date() > expiresAt) {
    await env.SESSIONS.delete(sessionKey);
    return jsonResponse({ error: "Session expired", valid: false }, 401, corsHeaders);
  }

  // Verify user still exists and is active
  const userDataRaw = await env.USERS_DB.get(`user:${sessionData.username}`);
  if (!userDataRaw) {
    await env.SESSIONS.delete(sessionKey);
    return jsonResponse({ error: "User no longer exists", valid: false }, 401, corsHeaders);
  }

  const userData = JSON.parse(userDataRaw);
  if (!userData.active) {
    await env.SESSIONS.delete(sessionKey);
    return jsonResponse({ error: "User account deactivated", valid: false }, 403, corsHeaders);
  }

  return jsonResponse(
    {
      valid: true,
      username: sessionData.username,
      email: userData.email,
      expires_at: sessionData.expires_at,
      created_at: sessionData.created_at,
    },
    200,
    corsHeaders
  );
}

async function handleRefresh(request, env, corsHeaders) {
  const authHeader = request.headers.get("Authorization");
  if (!authHeader || !authHeader.startsWith("Bearer ")) {
    return jsonResponse({ error: "Authorization header required" }, 401, corsHeaders);
  }

  const oldToken = authHeader.substring(7);
  const oldSessionKey = `session:${oldToken}`;
  const oldSessionDataRaw = await env.SESSIONS.get(oldSessionKey);

  if (!oldSessionDataRaw) {
    return jsonResponse({ error: "Invalid or expired session" }, 401, corsHeaders);
  }

  const oldSessionData = JSON.parse(oldSessionDataRaw);

  // Verify user still active
  const userDataRaw = await env.USERS_DB.get(`user:${oldSessionData.username}`);
  if (!userDataRaw) {
    await env.SESSIONS.delete(oldSessionKey);
    return jsonResponse({ error: "User no longer exists" }, 401, corsHeaders);
  }

  const userData = JSON.parse(userDataRaw);
  if (!userData.active) {
    await env.SESSIONS.delete(oldSessionKey);
    return jsonResponse({ error: "User account deactivated" }, 403, corsHeaders);
  }

  // Delete old session
  await env.SESSIONS.delete(oldSessionKey);

  // Create new session
  const newToken = await generateSessionToken();
  const sessionTTL = 24 * 60 * 60;
  const newSessionData = {
    username: oldSessionData.username,
    created_at: new Date().toISOString(),
    expires_at: new Date(Date.now() + sessionTTL * 1000).toISOString(),
    user_agent: request.headers.get("User-Agent") || "unknown",
    ip: request.headers.get("CF-Connecting-IP") || "unknown",
    refreshed_from: oldToken.substring(0, 8) + "...",
  };

  await env.SESSIONS.put(`session:${newToken}`, JSON.stringify(newSessionData), {
    expirationTtl: sessionTTL,
  });

  return jsonResponse(
    {
      message: "Session refreshed",
      session_token: newToken,
      expires_at: newSessionData.expires_at,
      username: newSessionData.username,
    },
    200,
    corsHeaders
  );
}

// Utility functions

function generateSalt() {
  const array = new Uint8Array(16);
  crypto.getRandomValues(array);
  return arrayBufferToHex(array.buffer);
}

async function generateSessionToken() {
  const array = new Uint8Array(32);
  crypto.getRandomValues(array);
  return arrayBufferToHex(array.buffer);
}

async function hashPassword(password, salt) {
  const encoder = new TextEncoder();
  const data = encoder.encode(salt + password);

  // Use PBKDF2-like iterative hashing with SHA-256
  let hash = data;
  for (let i = 0; i < 10000; i++) {
    const combined = new Uint8Array(hash.length + data.length);
    combined.set(hash instanceof Uint8Array ? hash : new Uint8Array(hash));
    combined.set(data, hash.length);
    hash = new Uint8Array(await crypto.subtle.digest("SHA-256", combined));
  }

  return arrayBufferToHex(hash instanceof ArrayBuffer ? hash : hash.buffer);
}

function arrayBufferToHex(buffer) {
  return Array.from(new Uint8Array(buffer))
    .map((b) => b.toString(16).padStart(2, "0"))
    .join("");
}

function timingSafeEqual(a, b) {
  if (a.length !== b.length) {
    return false;
  }
  let result = 0;
  for (let i = 0; i < a.length; i++) {
    result |= a.charCodeAt(i) ^ b.charCodeAt(i);
  }
  return result === 0;
}

async function incrementLoginAttempts(env, rateLimitKey, existingData) {
  let rateLimit;
  if (existingData) {
    rateLimit = JSON.parse(existingData);
    rateLimit.attempts += 1;
  } else {
    rateLimit = { attempts: 1 };
  }

  if (rateLimit.attempts >= 5) {
    rateLimit.locked_until = new Date(Date.now() + 15 * 60 * 1000).toISOString(); // 15 min lockout
  }

  const ttl = 15 * 60; // 15 minutes
  await env.SESSIONS.put(rateLimitKey, JSON.stringify(rateLimit), {
    expirationTtl: ttl,
  });
}

function jsonResponse(data, status = 200, corsHeaders = {}) {
  return new Response(JSON.stringify(data), {
    status,
    headers: {
      "Content-Type": "application/json",
      ...corsHeaders,
    },
  });
}